                 <button type="submit" className="w-full bg-primary text-gold py-4 rounded-2xl font-black uppercase hover:opacity-90 transition-all shadow-lg active:scale-95 text-xs md:text-sm">Đăng nhập</button>
                 <button type="button" onClick={() => setShowLogin(false)} className="text-gray-400 text-[10px] font-bold uppercase hover:text-primary">Quay lại</button>
              </form>
