      {/* Toast Notification */}
      {toast && (
        <div className={`fixed bottom-4 right-4 md:bottom-10 md:right-10 z-[500] px-6 md:px-8 py-3 md:py-4 rounded-2xl font-bold shadow-2xl animate-fadeIn flex items-center gap-3 border-2 text-xs md:text-sm ${
