              <div className="flex bg-gray-100 p-1 rounded-xl">
                <button 
                  onClick={() => setEditingMember({...editingMember, isMale: true})}
                  className={`px-4 md:px-6 py-2 rounded-lg text-[10px] md:text-xs font-black uppercase tracking-widest transition-all ${editingMember.isMale ? 'bg-primary text-white shadow-md' : 'text-gray-400'}`}
                >
                  Nam
                </button>
                <button 
                  onClick={() => setEditingMember({...editingMember, isMale: false})}
                  className={`px-4 md:px-6 py-2 rounded-lg text-[10px] md:text-xs font-black uppercase tracking-widest transition-all ${!editingMember.isMale ? 'bg-pink-600 text-white shadow-md' : 'text-gray-400'}`}
                >
                  Nữ
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-6">
                <h4 className="text-[10px] md:text-xs font-black uppercase tracking-widest text-primary bg-gray-100 px-4 py-2 rounded-lg">Thông tin chính</h4>
