              </div>

              <div className="space-y-6">
                <h4 className="text-[10px] md:text-xs font-black uppercase tracking-widest text-pink-900 bg-pink-50 px-4 py-2 rounded-lg">Thông tin Vợ / Chồng</h4>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Họ và tên Vợ / Chồng</label>
                  <input type="text" value={editingMember.spouseName || ''} onChange={(e) => setEditingMember({...editingMember, spouseName: e.target.value})} className="w-full border-2 border-pink-50 p-3 md:p-4 rounded-xl focus:border-pink-200 outline-none font-bold" placeholder="Nhập tên vợ/chồng..." />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Năm mất (Âm lịch) Vợ / Chồng</label>
