                </div>
              </div>
            </div>

            <div className="flex flex-col md:flex-row gap-4 mt-8 md:mt-12 pt-8 border-t">
              <button onClick={() => {
                const updateNode = (node: FamilyMember): FamilyMember => {
                  if (node.id === editingMember.id) return editingMember;
                  if (node.children) return { ...node, children: node.children.map(updateNode) };
                  return node;
                };
                updateData({ familyTree: updateNode(appData.familyTree) });
                setEditingMember(null);
                showToast("Đã lưu vào bộ nhớ tạm");
              }} className="bg-primary text-gold px-8 md:px-10 py-3 md:py-4 rounded-2xl font-black uppercase shadow-lg hover:opacity-90 transition-all flex-1 text-xs md:text-sm">Lưu thay đổi</button>
              <button onClick={() => setEditingMember(null)} className="bg-gray-100 text-gray-600 px-8 md:px-10 py-3 md:py-4 rounded-2xl font-black uppercase hover:bg-gray-200 transition-all text-xs md:text-sm">Hủy</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { EventItem, EventType } from '../types';

interface EventsProps {
  events: EventItem[];
  isAdmin: boolean;
  onAddEvent: (event: EventItem) => void;
  onDeleteEvent: (id: string) => void;
}

const Events: React.FC<EventsProps> = ({ events, isAdmin, onAddEvent, onDeleteEvent }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getLunarLabel = (day: number) => {
    // Mock simple lunar cycle for visual aid
    const lunarDay = (day % 29) + 1;
    return lunarDay;
  };

  const calendarData = useMemo(() => {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();

    const firstDayOfMonth = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const days = [];
    // Padding for previous month
    for (let i = 0; i < firstDayOfMonth; i++) {
      days.push({ day: null, currentMonth: false });
    }
    // Days of current month
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${i.toString().padStart(2, '0')}`;
      const dayEvents = events.filter(e => e.solarDate === dateStr);
      days.push({ 
        day: i, 
        currentMonth: true, 
        dateStr,
        hasEvent: dayEvents.length > 0,
        hasDeathAnniversary: dayEvents.some(e => e.type === 'giỗ')
      });
    }
    return days;
  }, [viewDate, events]);

  const changeMonth = (offset: number) => {
    setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + offset, 1));
  };

  const todaySolarStr = currentTime.toISOString().split('T')[0];
  const todayEvents = events.filter(e => e.solarDate === todaySolarStr);
  const upcomingEvents = events
    .filter(e => e.solarDate > todaySolarStr)
    .sort((a, b) => a.solarDate.localeCompare(b.solarDate));

  return (
    <div className="max-w-4xl mx-auto animate-fadeIn space-y-6 pb-20">
      {/* Header Sự kiện */}
      <div className="bg-red-800 rounded-t-[2rem] p-6 flex justify-between items-center shadow-xl relative overflow-hidden border-b-4 border-gold/30">
        <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/oriental-tiles.png')]"></div>
        <div className="z-10">
          <h2 className="text-3xl font-traditional text-white font-black m-0">Sự Kiện Gia Tộc</h2>
          <p className="text-gold/70 text-[10px] font-black uppercase tracking-widest mt-1">Lịch vạn niên & Lễ nghi</p>
        </div>
        {isAdmin && (
          <button 
            onClick={() => {
              const title = prompt("Tên sự kiện:");
              const date = prompt("Ngày (YYYY-MM-DD):", todaySolarStr);
              const isGio = confirm("Đây có phải là ngày Giỗ không?");
              if (title && date) {
                onAddEvent({
                  id: Date.now().toString(),
                  title,
                  solarDate: date,
                  type: isGio ? 'giỗ' : 'họp mặt'
                });
              }
            }}
            className="bg-gold text-red-950 px-6 py-2 rounded-full text-xs font-black uppercase hover:bg-white transition-all flex items-center gap-2 z-10 shadow-lg active:scale-95"
          >
            <span>+</span> Thêm sự kiện
          </button>
        )}
      </div>

      {/* Lịch Widget */}
      <div className="bg-white/80 backdrop-blur-xl p-6 md:p-10 rounded-[2rem] shadow-2xl border border-red-900/5">
        <div className="flex justify-between items-center mb-10">
          <button onClick={() => changeMonth(-1)} className="w-12 h-12 flex items-center justify-center rounded-full bg-red-50 text-red-900 hover:bg-red-900 hover:text-white transition-all shadow-sm">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
          </button>

          <div className="text-center">
            <h3 className="text-3xl font-traditional font-black text-red-950">
              Tháng {viewDate.getMonth() + 1}
              <span className="text-red-900/30 ml-3">/ {viewDate.getFullYear()}</span>
            </h3>
            <div className="flex justify-center gap-2 mt-2">
               <span className="w-2 h-2 rounded-full bg-red-700"></span>
               <span className="w-2 h-2 rounded-full bg-gold"></span>
               <span className="w-2 h-2 rounded-full bg-red-950"></span>
            </div>
          </div>

          <button onClick={() => changeMonth(1)} className="w-12 h-12 flex items-center justify-center rounded-full bg-red-50 text-red-900 hover:bg-red-900 hover:text-white transition-all shadow-sm">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
          </button>
        </div>

        <div className="grid grid-cols-7 gap-2 md:gap-4">
          {['CN', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7'].map((d, idx) => (
            <div key={d} className={`text-center text-[10px] md:text-xs font-black mb-4 tracking-widest ${idx === 0 ? 'text-red-600' : 'text-gray-400'}`}>{d}</div>
          ))}
          {calendarData.map((item, i) => {
            const isToday = item.dateStr === todaySolarStr;
            return (
              <div 
                key={i} 
                className={`
                  relative flex flex-col items-center justify-center py-4 md:py-6 rounded-2xl md:rounded-3xl transition-all cursor-pointer group
                  ${item.day ? 'hover:bg-red-50' : 'opacity-0 pointer-events-none'}
                  ${isToday ? 'bg-red-900 shadow-xl scale-105 z-10' : 'bg-transparent'}
                  ${item.hasDeathAnniversary && !isToday ? 'bg-red-50 border-2 border-red-900/20' : ''}
                `}
              >
                {item.hasDeathAnniversary && (
                  <div className="absolute -top-1 -right-1 text-xs md:text-sm animate-pulse z-20">🕯️</div>
                )}
